// Highly simplified conceptual C socket responder sketch
#include <stdio.h>
#include <sys/socket.h>
#include <unistd.h>

void handle_request(int client_fd) {
    char response[] = "HTTP/1.1 200 OK\r\nContent-Type: text/plain\r\n\r\nHello";
    write(client_fd, response, sizeof(response) - 1);
    close(client_fd);
}

#include <stdio.h>
#include <string.h>

struct MapEntry { char key[20]; int value; };

int lookup(struct MapEntry* map, int size, const char* key) {
    for(int i = 0; i < size; i++) {
        if(strcmp(map[i].key, key) == 0) return map[i].value;
    }
    return -1;
}
